import{c as t,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"An update on recent Claude Code quality reports","description":"","frontmatter":{"title":"An update on recent Claude Code quality reports","author":"Anthropic","date":"2026-04-23T00:00:00.000Z","source":"https://www.anthropic.com/engineering/april-23-postmortem","tags":["agent-harness","anthropic","research","claude-code","quality"]},"headers":[],"relativePath":"research/agent-harness/references/2026-04-23-anthropic-april-23-postmortem.md","filePath":"research/agent-harness/references/2026-04-23-anthropic-april-23-postmortem.md","lastUpdated":1779894392000}'),s={name:"research/agent-harness/references/2026-04-23-anthropic-april-23-postmortem.md"};function n(i,e,d,p,l,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="an-update-on-recent-claude-code-quality-reports" tabindex="-1">An update on recent Claude Code quality reports <a class="header-anchor" href="#an-update-on-recent-claude-code-quality-reports" aria-label="Permalink to &quot;An update on recent Claude Code quality reports&quot;">​</a></h1><p><strong>Published:</strong> Apr 23, 2026</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Anthropic identified and resolved three separate issues affecting Claude Code quality reported over the past month. The API remained unaffected throughout.</p><h2 id="the-three-issues" tabindex="-1">The Three Issues <a class="header-anchor" href="#the-three-issues" aria-label="Permalink to &quot;The Three Issues&quot;">​</a></h2><p><strong>1. Reasoning Effort Default Change</strong> On March 4, the team shifted Claude Code&#39;s default reasoning from <code>high</code> to <code>medium</code> to reduce latency issues. Users preferred intelligence over speed, so this was reverted April 7. The company now defaults to <code>xhigh</code> for Opus 4.7 and <code>high</code> for other models.</p><p><strong>2. Caching Bug Caused Memory Loss</strong> A March 26 optimization introduced a bug where Claude&#39;s reasoning history was cleared every turn instead of once per session. This made the model appear forgetful and repetitive, affecting Sonnet 4.6 and Opus 4.6. Fixed April 10, the issue persisted because &quot;internal experiments and display changes suppressed visibility.&quot;</p><p><strong>3. System Prompt Verbosity Instruction</strong> A new instruction limiting response length to &quot;keep text between tool calls to ≤25 words&quot; shipped April 16 with Opus 4.7. Broader evaluation testing revealed a 3% intelligence drop, prompting immediate reversion on April 20.</p><h2 id="response-and-prevention" tabindex="-1">Response and Prevention <a class="header-anchor" href="#response-and-prevention" aria-label="Permalink to &quot;Response and Prevention&quot;">​</a></h2><p>Anthropic reset usage limits for all subscribers and outlined preventive measures: broader internal testing on public builds, enhanced Code Review tools, stricter system prompt controls with comprehensive evaluations, and gradual rollouts for intelligence-affecting changes.</p>',10)])])}const m=t(s,[["render",n]]);export{h as __pageData,m as default};
